using System;
using System.Collections.Generic;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext(string dbName = null)
        {
            var context = CreateInMemoryContext(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            // Add instructor (inherits from Person, ID auto-generated)
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            // Add department linked to instructor
            var department = new Department
            {
                Name = "English",
                Budget = 350000m,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(department);
            context.SaveChanges();

            // Add course (CourseID is NOT auto-generated)
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = department.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Courses.Add(course);
            context.SaveChanges();

            // Add course assignment
            var courseAssignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            context.CourseAssignments.Add(courseAssignment);
            context.SaveChanges();

            // Add students
            var student1 = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student2 = new Student
            {
                FirstMidName = "Meredith",
                LastName = "Alonso",
                EnrollmentDate = DateTime.Parse("2012-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student3 = new Student
            {
                FirstMidName = "Arturo",
                LastName = "Anand",
                EnrollmentDate = DateTime.Parse("2013-09-01"),
                Enrollments = new List<Enrollment>()
            };
            context.Students.AddRange(student1, student2, student3);
            context.SaveChanges();

            // Add enrollment
            var enrollment = new Enrollment
            {
                StudentID = student1.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();
        }

        public static void DrainNotificationQueue()
        {
            using var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }
    }
}

