using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_ValidInputs_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 5);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        [DataRow(10, 3, 4, DisplayName = "10 items pageSize 3 = 4 pages")]
        [DataRow(10, 5, 2, DisplayName = "10 items pageSize 5 = 2 pages")]
        [DataRow(10, 10, 1, DisplayName = "10 items pageSize 10 = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items = 0 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item pageSize 10 = 1 page")]
        [DataRow(11, 10, 2, DisplayName = "11 items pageSize 10 = 2 pages")]
        [DataRow(100, 25, 4, DisplayName = "100 items pageSize 25 = 4 pages")]
        public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_WithItems_AddsAllItemsToList()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 1, 5);

            // Assert
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_ThirdPage_ReturnsTrue()
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), 30, 3, 5);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_NotOnLastPage_ReturnsTrue()
        {
            // Act (page 1 of 2)
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            // Act (page 2 of 2)
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            // Act (page 1 of 1)
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_MiddlePage_ReturnsCorrectSlice()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
            Assert.AreEqual(2, result.PageIndex);
        }

        [TestMethod]
        public void Create_LastPagePartial_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 12).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 5);

            // Assert
            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
            Assert.IsFalse(result.HasNextPage);
            Assert.IsTrue(result.HasPreviousPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyListWithZeroPages()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_ExactPageSize_SinglePage()
        {
            // Arrange
            var source = Enumerable.Range(1, 5).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasNextPage);
            Assert.IsFalse(result.HasPreviousPage);
        }

        [TestMethod]
        public void Create_PageSizeOne_PaginatesCorrectly()
        {
            // Arrange
            var source = Enumerable.Range(1, 3).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 1);

            // Assert
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(2, result[0]);
            Assert.AreEqual(3, result.TotalPages);
            Assert.IsTrue(result.HasPreviousPage);
            Assert.IsTrue(result.HasNextPage);
        }
    }
}

