using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            var result = sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void SendNotification_ThenReceive_ReturnsCorrectNotification()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            sut.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "Admin");
            var result = sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Student", result.EntityType);
            Assert.AreEqual("1", result.EntityId);
            Assert.AreEqual("CREATE", result.Operation);
            Assert.AreEqual("Admin", result.CreatedBy);
            Assert.IsFalse(result.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectCreateMessage()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            sut.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE);
            var result = sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student 'Carson Alexander' has been created", result.Message);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectUpdateMessage()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);
            var result = sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been updated", result.Message);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectDeleteMessage()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
            var result = sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("Department 'Engineering' has been deleted", result.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            sut.SendNotification("Student", "42", EntityOperation.CREATE);
            var result = sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 42) has been created", result.Message);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var result = sut.ReceiveNotification();

            // Assert
            Assert.AreEqual("System", result.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_MultipleMessages_ReceivedInFIFOOrder()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act
            sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
