            var after = DateTime.Now.AddSeconds(1);
            var result = sut.ReceiveNotification();

            // Assert
            Assert.IsTrue(result.CreatedAt >= before && result.CreatedAt <= after,
                $"CreatedAt {result.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void MarkAsRead_ValidId_DoesNotThrow()
        {
            // Arrange
            using var sut = new NotificationService();

            // Act & Assert (no-op, should not throw)
            sut.MarkAsRead(1);
            sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_CalledMultipleTimes_DoesNotThrow()
        {
            // Arrange
            var sut = new NotificationService();

            // Act & Assert
            sut.Dispose();
            sut.Dispose(); // Should not throw
        }

