using System;
using System.Collections.Generic;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class ModelTests
    {
        // --- Person / Student / Instructor FullName ---

        [TestMethod]
        public void Student_FullName_ReturnsLastCommaFirst()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Today
            };

            // Act & Assert
            Assert.AreEqual("Alexander, Carson", student.FullName);
        }

        [TestMethod]
        public void Instructor_FullName_ReturnsLastCommaFirst()
        {
            // Arrange
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Today
            };

            // Act & Assert
            Assert.AreEqual("Abercrombie, Kim", instructor.FullName);
        }

        [TestMethod]
        [DataRow("Doe", "Jane", "Doe, Jane", DisplayName = "Standard names")]
        [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
        [DataRow("X", "Y", "X, Y", DisplayName = "Single character names")]
        public void Person_FullName_FormatsCorrectly(string last, string first, string expected)
        {
            // Arrange
            var student = new Student
            {
                LastName = last,
                FirstMidName = first,
                EnrollmentDate = DateTime.Today
            };

            // Act & Assert
            Assert.AreEqual(expected, student.FullName);
        }

        // --- ErrorViewModel ---

        [TestMethod]
        public void ErrorViewModel_ShowRequestId_TrueWhenRequestIdSet()
        {
            // Arrange
            var model = new ErrorViewModel { RequestId = "abc123" };

            // Assert
            Assert.IsTrue(model.ShowRequestId);
        }

        [TestMethod]
        public void ErrorViewModel_ShowRequestId_FalseWhenRequestIdNull()
        {
            // Arrange
            var model = new ErrorViewModel { RequestId = null };

            // Assert
            Assert.IsFalse(model.ShowRequestId);
        }

        [TestMethod]
        public void ErrorViewModel_ShowRequestId_FalseWhenRequestIdEmpty()
        {
            // Arrange
            var model = new ErrorViewModel { RequestId = "" };

            // Assert
            Assert.IsFalse(model.ShowRequestId);
        }

        // --- Course properties ---

        [TestMethod]
        public void Course_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.jpg"
            };

            // Assert
            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/images/chem.jpg", course.TeachingMaterialImagePath);
        }

        // --- Department properties ---

        [TestMethod]
        public void Department_Properties_SetAndGetCorrectly()
        {
            // Arrange
            var startDate = DateTime.Parse("2007-09-01");

            // Act
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000m,
                StartDate = startDate,
                InstructorID = 5
            };

            // Assert
            Assert.AreEqual(1, dept.DepartmentID);
            Assert.AreEqual("English", dept.Name);
            Assert.AreEqual(350000m, dept.Budget);
            Assert.AreEqual(startDate, dept.StartDate);
            Assert.AreEqual(5, dept.InstructorID);
        }

        [TestMethod]
        public void Department_InstructorID_CanBeNull()
        {
            // Arrange & Act
            var dept = new Department { InstructorID = null };

            // Assert
            Assert.IsNull(dept.InstructorID);
        }

        // --- Enrollment properties ---

        [TestMethod]
        public void Enrollment_Grade_CanBeNull()
        {
            // Arrange & Act
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = null
            };

            // Assert
            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        [DataRow(Grade.A, DisplayName = "Grade A")]
        [DataRow(Grade.B, DisplayName = "Grade B")]
        [DataRow(Grade.C, DisplayName = "Grade C")]
        [DataRow(Grade.D, DisplayName = "Grade D")]
        [DataRow(Grade.F, DisplayName = "Grade F")]
        public void Enrollment_Grade_AcceptsAllGradeValues(Grade grade)
        {
            // Arrange & Act
            var enrollment = new Enrollment { Grade = grade };

            // Assert
            Assert.AreEqual(grade, enrollment.Grade);
        }

        // --- Notification model ---

        [TestMethod]
        public void Notification_Properties_SetAndGetCorrectly()
        {
            // Arrange
            var now = DateTime.Now;

            // Act
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            // Assert
            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New student created", notification.Message);
            Assert.AreEqual(now, notification.CreatedAt);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void Notification_ReadAt_CanBeSet()
        {
            // Arrange
            var readAt = DateTime.Now;

            // Act
            var notification = new Notification
            {
                IsRead = true,
                ReadAt = readAt
            };

            // Assert
            Assert.IsTrue(notification.IsRead);
            Assert.AreEqual(readAt, notification.ReadAt);
        }

        // --- EntityOperation enum ---

        [TestMethod]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.AreEqual(0, (int)EntityOperation.CREATE);
            Assert.AreEqual(1, (int)EntityOperation.UPDATE);
            Assert.AreEqual(2, (int)EntityOperation.DELETE);
        }

        // --- Grade enum ---

        [TestMethod]
        public void Grade_HasExpectedValues()
        {
            Assert.AreEqual(0, (int)Grade.A);
            Assert.AreEqual(1, (int)Grade.B);
            Assert.AreEqual(2, (int)Grade.C);
            Assert.AreEqual(3, (int)Grade.D);
            Assert.AreEqual(4, (int)Grade.F);
        }

        // --- OfficeAssignment ---

        [TestMethod]
        public void OfficeAssignment_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var office = new OfficeAssignment
            {
                InstructorID = 10,
                Location = "Smith 17"
            };

            // Assert
            Assert.AreEqual(10, office.InstructorID);
            Assert.AreEqual("Smith 17", office.Location);
        }

        // --- CourseAssignment ---

        [TestMethod]
        public void CourseAssignment_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var ca = new CourseAssignment
            {
                InstructorID = 10,
                CourseID = 1050
            };

            // Assert
            Assert.AreEqual(10, ca.InstructorID);
            Assert.AreEqual(1050, ca.CourseID);
        }

        // --- View Models ---

        [TestMethod]
        public void AssignedCourseData_Properties_SetAndGetCorrectly()
        {
            // Arrange & Act
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            // Assert
            Assert.AreEqual(1050, data.CourseID);
            Assert.AreEqual("Chemistry", data.Title);
            Assert.IsTrue(data.Assigned);
        }

        [TestMethod]
        public void EnrollmentDateGroup_Properties_SetAndGetCorrectly()
        {
            // Arrange
            var date = DateTime.Parse("2012-09-01");

            // Act
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = date,
                StudentCount = 5
            };

            // Assert
            Assert.AreEqual(date, group.EnrollmentDate);
            Assert.AreEqual(5, group.StudentCount);
        }

        [TestMethod]
        public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
        {
            // Arrange & Act
            var group = new EnrollmentDateGroup { EnrollmentDate = null };

            // Assert
            Assert.IsNull(group.EnrollmentDate);
        }

        [TestMethod]
        public void InstructorIndexData_Properties_SetAndGetCorrectly()
        {
            // Arrange
            var instructors = new List<Instructor>();
            var courses = new List<Course>();
            var enrollments = new List<Enrollment>();

            // Act
            var data = new InstructorIndexData
            {
                Instructors = instructors,
                Courses = courses,
                Enrollments = enrollments
            };

            // Assert
            Assert.AreSame(instructors, data.Instructors);
            Assert.AreSame(courses, data.Courses);
            Assert.AreSame(enrollments, data.Enrollments);
        }

        // --- Student navigation properties ---

        [TestMethod]
        public void Student_Enrollments_InitializesAsEmptyCollection()
        {
            // Arrange & Act
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.Today,
                Enrollments = new List<Enrollment>()
            };

            // Assert
            Assert.IsNotNull(student.Enrollments);
            Assert.AreEqual(0, student.Enrollments.Count);
        }

        // --- Instructor navigation properties ---

        [TestMethod]
        public void Instructor_CourseAssignments_InitializesAsEmptyCollection()
        {
            // Arrange & Act
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "User",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            // Assert
            Assert.IsNotNull(instructor.CourseAssignments);
            Assert.AreEqual(0, instructor.CourseAssignments.Count);
        }
    }
}

