using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            // We seeded 3 students with different enrollment dates
            Assert.IsTrue(model.Count > 0, "Should have at least one enrollment date group");
        }

        [TestMethod]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            // Act
            var result = _controller.About() as ViewResult;
            var model = result.Model as System.Collections.Generic.List<EnrollmentDateGroup>;

            // Assert
            // 3 students with 3 different dates → 3 groups
            Assert.AreEqual(3, model.Count);
            Assert.IsTrue(model.All(g => g.StudentCount > 0), "Each group should have at least one student");
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            // Act
            var result = _controller.Contact() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            // Act
            var result = _controller.Error();

            // Assert
            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessageAndReturnsView()
        {
            // Act
            var result = _controller.Unauthorized() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

