using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // --- Index ---

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithAllStudents()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count); // 3 seeded students
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Anand", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Alexander", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert - 2010 < 2012 < 2013
            Assert.AreEqual("Alexander", model[0].LastName); // 2010
            Assert.AreEqual("Alonso", model[1].LastName);    // 2012
            Assert.AreEqual("Anand", model[2].LastName);     // 2013
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert - 2013 > 2012 > 2010
            Assert.AreEqual("Anand", model[0].LastName);     // 2013
            Assert.AreEqual("Alonso", model[1].LastName);    // 2012
            Assert.AreEqual("Alexander", model[2].LastName); // 2010
        }

        [TestMethod]
        public void Index_SearchString_FiltersResults()
        {
            // Act - search for "Al" matches Alexander and Alonso
            var result = _controller.Index(null, null, "Al", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void Index_SearchStringFirstName_FiltersResults()
        {
            // Act - search by first name "Carson"
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsToPage1()
        {
            // Act - providing searchString resets page to 1
            var result = _controller.Index(null, null, "Alexander", 5) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            // Act - null searchString uses currentFilter
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            // Act
            _controller.Index(null, null, null, null);

            // Assert
            Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
        }

        [TestMethod]
        public void Index_WithSortOrder_SetsViewBagCorrectly()
        {
            // Act
            _controller.Index("Date", null, null, null);

            // Assert
            Assert.AreEqual("", _controller.ViewBag.NameSortParm); // non-empty sortOrder → ""
            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm); // "Date" → "date_desc"
        }

        // --- Details ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var studentId = _context.Students.First().ID;

            // Act
            var result = _controller.Details(studentId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(studentId, model.ID);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            // Act
            var result = _controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            // Verify student was added to the database
            Assert.AreEqual(4, _context.Students.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };
            _controller.ModelState.AddModelError("Error", "Test error");

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual(student, result.Model);
        }

        [TestMethod]
        public void Create_Post_MinValueEnrollmentDate_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_OutOfRangeEnrollmentDate_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = new DateTime(1752, 12, 31) // Before valid range
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        // --- Edit GET ---

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var studentId = _context.Students.First().ID;

            // Act
            var result = _controller.Edit(studentId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(studentId, model.ID);
        }

        [TestMethod]
        public void Edit_Get_NonexistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // --- Edit POST ---

        [TestMethod]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            // Arrange
            var existingStudent = _context.Students.First();
            // Detach to simulate round-trip from form
            _context.Entry(existingStudent).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = existingStudent.ID,
                FirstMidName = "UpdatedFirst",
                LastName = "UpdatedLast",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            // Act
            var result = _controller.Edit(updatedStudent) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_MinValueEnrollmentDate_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Edit(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        // --- Delete GET ---

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var studentId = _context.Students.First().ID;

            // Act
            var result = _controller.Delete(studentId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(studentId, model.ID);
        }

        [TestMethod]
        public void Delete_Get_NonexistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // --- Delete POST ---

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            // Arrange
            var studentId = _context.Students.First().ID;
            var initialCount = _context.Students.Count();

            // Act
            var result = _controller.DeleteConfirmed(studentId) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(initialCount - 1, _context.Students.Count());
        }
    }
}

