using Moq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _mockEnv;
        private Mock<ILogger<CoursesController>> _mockLogger;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/fake/wwwroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/fake/content");
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // --- Index ---

        [TestMethod]
        public void Index_ReturnsViewWithCourseList()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count); // 1 seeded course
            Assert.AreEqual("Chemistry", model[0].Title);
        }

        // --- Details ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Details(1050) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(1050, model.CourseID);
            Assert.AreEqual("Chemistry", model.Title);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.DepartmentID);
            var selectList = _controller.ViewBag.DepartmentID as SelectList;
            Assert.IsNotNull(selectList);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidModelNoFile_Saves()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 2000,
                Title = "Physics",
                Credits = 4,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            // Act
            var result = _controller.Create(course, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Courses.Count());
            Assert.IsNotNull(_context.Courses.Find(2000));
        }

