            {
                CourseID = 3000,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("document.pdf");
            mockFile.Setup(f => f.Length).Returns(100);

            // Act
            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

