            {
                CourseID = 3000,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("image.jpg");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB > 5MB limit

            // Act
