using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _mockEnv;
        private Mock<ILogger<CoursesController>> _mockLogger;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/fake/wwwroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/fake/content");
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // --- Index ---

        [TestMethod]
        public void Index_ReturnsViewWithCourseList()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count); // 1 seeded course
            Assert.AreEqual("Chemistry", model[0].Title);
        }

        // --- Details ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Details(1050) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(1050, model.CourseID);
            Assert.AreEqual("Chemistry", model.Title);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.DepartmentID);
            var selectList = _controller.ViewBag.DepartmentID as SelectList;
            Assert.IsNotNull(selectList);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidModelNoFile_Saves()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 2000,
                Title = "Physics",
                Credits = 4,
                DepartmentID = _context.Departments.First().DepartmentID
            };

            // Act
            var result = _controller.Create(course, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Courses.Count());
            Assert.IsNotNull(_context.Courses.Find(2000));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var course = new Course { CourseID = 3000, Title = "Test", Credits = 3 };
            _controller.ModelState.AddModelError("Error", "Test error");

            // Act
            var result = _controller.Create(course, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 3000,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("document.pdf");
            mockFile.Setup(f => f.Length).Returns(100);

            // Act
            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 3000,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("image.jpg");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB > 5MB limit

            // Act
            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        [DataRow(".txt", DisplayName = "Text file")]
        [DataRow(".pdf", DisplayName = "PDF file")]
        [DataRow(".exe", DisplayName = "Executable")]
        [DataRow(".doc", DisplayName = "Word document")]
        public void Create_Post_VariousInvalidExtensions_ReturnsError(string extension)
        {
            // Arrange
            var course = new Course
            {
                CourseID = 3000,
                Title = "Test",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns($"file{extension}");
            mockFile.Setup(f => f.Length).Returns(100);

            // Act
            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        // --- Edit GET ---

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Edit((int?)1050) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(1050, model.CourseID);
        }

        [TestMethod]
        public void Edit_Get_NonexistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit((int?)9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // --- Edit POST ---

        [TestMethod]
        public void Edit_Post_ValidModelNoFile_UpdatesAndRedirects()
        {
            // Arrange
            var existingCourse = _context.Courses.First();
            _context.Entry(existingCourse).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = existingCourse.CourseID,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = existingCourse.DepartmentID
            };

            // Act
            var result = _controller.Edit(updatedCourse, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("doc.pdf");
            mockFile.Setup(f => f.Length).Returns(100);

            // Act
            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Edit_Post_FileTooLarge_ReturnsViewWithError()
        {
            // Arrange
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = _context.Departments.First().DepartmentID
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("image.png");
            mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB > 5MB limit

            // Act
            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        // --- Delete GET ---

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            // Act
            var result = _controller.Delete(1050) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(1050, model.CourseID);
        }

        // --- Delete POST ---

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            // Arrange
            var initialCount = _context.Courses.Count();

            // Act
            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(initialCount - 1, _context.Courses.Count());
        }
    }
}

