using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class DepartmentsControllerTests
    {
        private SchoolContext _context;
        private DepartmentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _controller = new DepartmentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // --- Index ---

        [TestMethod]
        public void Index_ReturnsViewWithDepartments()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count); // 1 seeded department
            Assert.AreEqual("English", model[0].Name);
        }

        // --- Details ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            // Arrange
            var deptId = _context.Departments.First().DepartmentID;

            // Act
            var result = _controller.Details(deptId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual("English", model.Name);
        }

        [TestMethod]
        public void Details_NonexistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.InstructorID);
            var selectList = _controller.ViewBag.InstructorID as SelectList;
            Assert.IsNotNull(selectList);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidModel_SavesAndRedirects()
        {
            // Arrange
            var department = new Department
            {
                Name = "Mathematics",
                Budget = 100000m,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = _context.Instructors.First().ID
            };

            // Act
            var result = _controller.Create(department) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Departments.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            var department = new Department { Name = "Test" };
            _controller.ModelState.AddModelError("Error", "Test error");

            // Act
            var result = _controller.Create(department) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit GET ---

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            // Arrange
            var deptId = _context.Departments.First().DepartmentID;

            // Act
