using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // --- Index ---

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Instructors);
            Assert.AreEqual(1, model.Instructors.Count()); // 1 seeded instructor
        }

        [TestMethod]
        public void Index_WithInstructorId_ReturnsCoursesForInstructor()
        {
            // Arrange
            var instructorId = _context.Instructors.First().ID;

            // Act
            var result = _controller.Index(instructorId, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            // Assert
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count()); // 1 course assigned
            Assert.AreEqual(instructorId, _controller.ViewBag.InstructorID);
        }

        [TestMethod]
        public void Index_WithInstructorIdAndCourseId_ReturnsEnrollments()
        {
            // Arrange
            var instructorId = _context.Instructors.First().ID;
            var courseId = 1050;

            // Act
            var result = _controller.Index(instructorId, courseId) as ViewResult;
            var model = result.Model as InstructorIndexData;

            // Assert
            Assert.IsNotNull(model.Enrollments);
            Assert.AreEqual(1, model.Enrollments.Count()); // 1 enrollment for chemistry
            Assert.AreEqual(courseId, _controller.ViewBag.CourseID);
        }

        // --- Details ---

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var instructorId = _context.Instructors.First().ID;

            // Act
            var result = _controller.Details(instructorId) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual("Abercrombie", model.LastName);
        }

        [TestMethod]
        public void Details_NonexistentId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Details(9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithCourseData()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
            Assert.IsNotNull(_controller.ViewBag.Courses);
        }

        [TestMethod]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            // Act
            _controller.Create();
            var courseData = _controller.ViewBag.Courses as List<AssignedCourseData>;

            // Assert
            Assert.IsNotNull(courseData);
            Assert.AreEqual(1, courseData.Count); // 1 seeded course
            Assert.IsFalse(courseData[0].Assigned); // Not assigned to new instructor
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidModelNoSelectedCourses_SavesAndRedirects()
        {
            // Arrange
            var instructor = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            // Arrange
            var instructor = new Instructor
            {
                FirstMidName = "Roger",
                LastName = "Harui",
                HireDate = DateTime.Parse("1998-07-01")
            };
            var selectedCourses = new[] { "1050" };

            // Act
            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var savedInstructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "Harui");
            Assert.AreEqual(1, savedInstructor.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsViewWithCourseData()
        {
            // Arrange
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };
            _controller.ModelState.AddModelError("Error", "Test error");

            // Act
            var result = _controller.Create(instructor, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.Courses);
        }

        // --- Delete GET ---

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var instructorId = _context.Instructors.First().ID;

